SELECT DISTINCT ORDERH.UF_SHIPMENTREF AS SHIPMENT_REF, ORDERH.REF AS ORDER_NUMBER, ORDERH.UF_CSA AS EAA, ORDERH.CUSTCODE, ORDERH.COMPANY, ORDERH.OHINVDATE, case when ORDERI.PRODUCT like '*%' then ORDERI.PRODUCT ELSE '' end as PRODUCT, case when ORDERI.PRODUCT like '*%' then ORDERI.COST ELSE NULL end as COST, case when ORDERI.PRODUCT like '*%' then ORDERI.QUANTITY ELSE NULL end as QUANTITY, case when ORDERI.PRODUCT like '*%' then ORDERI.COST * ORDERI.QUANTITY ELSE NULL end as TOTAL_COST FROM ORDERH LEFT JOIN ORDERI ON ORDERH.REF = ORDERI.REF WHERE ORDERH.OHINVDATE > CURRENT_DATE - 365 ORDER BY ORDERH.OHINVDATE DESC, SHIPMENT_REF, PRODUCT DESC
